class Login(graphene.Mutation):
    """User login mutation returning JWT tokens"""

    class Arguments:
        email = graphene.String(required=True)
        password = graphene.String(required=True)

    access_token = graphene.String()
    refresh_token = graphene.String()
    user = graphene.Field(UserType)

    @classmethod
    def mutate(cls, root, info, email, password):
        user = authenticate(email=email, password=password)
        if user:
            tokens = generate_jwt_tokens(user)
            return Login(
                access_token=tokens["access"],
                refresh_token=tokens["refresh"],
                user=user
            )
        raise GraphQLError("Invalid credentials")

def cache_by_id(model, timeout=3600):
    """Cache decorator for model lookups by ID"""
    def decorator(func):
        @wraps(func)
        def wrapper(self, info, id=None, **kwargs):
            if id:
                cache_key = f"{model.__name__}:{id}"
                cached = cache.get(cache_key)
                if cached:
                    return cached
                result = func(self, info, id=id, **kwargs)
                if result:
                    cache.set(cache_key, result, timeout)
                return result
            return func(self, info, **kwargs)
        return wrapper
    return decorator

class CreatePlaylist(BaseMutation):
    """Create a new playlist"""

    class Arguments:
        input = CreatePlaylistInput(required=True)

    @classmethod
    def mutate(cls, root, info, input):
        user = info.context.user
        if not user.is_authenticated:
            raise PermissionDenied("Authentication required")

        playlist = Playlist.objects.create(
            user=user,
            name=input.name,
            description=input.description,
            is_public=input.is_public,
            is_collaborative=input.is_collaborative
        )
        return cls.success_response(
            data=playlist,
            message="Playlist created successfully"
        )

